import React from "react";
import "../styles/News.css";

const articles = [
  {
    id: 1,
    title:
      "LENIENCY IN CRIMINAL SENTENCE FOR JUSTICE COLLABORATORS WHO SUPPORTS LAW ENFORCEMENT AUTHORITIES BY UNCOVERING CRIMINAL CASES",
    date: "06 February, 2025",
    image: "/images/justice.jpg", // Replace with actual path
    description:
      "The key to a successful criminal law enforcement depends on the evidence that has been...",
  },
  {
    id: 2,
    title:
      "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/open-source.jpg", // Replace with actual path
    description:
      "How is open source regulated in the copyright law in Indonesia? Despite its nature, which allows public...",
  },
  {
    id: 3,
    title:
      "Reformation of Indonesian Criminal Law: A Comparison of the Current Criminal Code (KUHP) and the New National Criminal Code (KUHP Nasional)",
    date: "20 December, 2024",
    image: "/images/gavel.jpg", // Replace with actual path
    description:
      "The current Criminal Code (KUHP), also known as the Wetboek van Strafrecht (WS), is a legacy from the...",
  },
];

const News = () => {
  return (
    <div className="News">
      <h2>News & Articles</h2>
      <div className="news-container">
        {articles.map((article) => (
          <div className="news-card" key={article.id}>
            <img src={article.image} alt={article.title} className="news-image" />
            <div className="news-content">
              <h3>{article.title}</h3>
              <p className="news-date">📅 {article.date}</p>
              <p className="news-description">{article.description}</p>
              <button className="news-button">Read More</button>
            </div>
          </div>
        ))}
      </div>
      <button className="view-more">View more →</button>
    </div>
  );
};

export default News;
